// Package escalation implements a MinPower-only escalation ladder used by
// the execute-bead loop to pick the next power floor after a substantive
// failure. The ladder reasons about Power values only — it never inspects
// provider names, model IDs, harness names, or any other vendor-identifying
// attributes. This keeps escalation portable across catalogs that disagree
// on which vendor sits at which tier.
package escalation

import (
	"errors"
	"fmt"
	"sort"

	agentlib "github.com/DocumentDrivenDX/fizeau"
)

// ErrLadderExhausted is returned by Ladder.Next when no power tier above
// the supplied actualPower exists in the catalog. Power escalation cannot
// proceed any further at this catalog.
var ErrLadderExhausted = errors.New("escalation: ladder exhausted; no higher power tier in catalog")

// NoViableProviderError signals that the next catalog tier above the
// caller's actualPower has no viable provider — i.e., every model at that
// tier is either unavailable or not auto-routable. The loop bumps further
// by calling Next(Floor) to skip past this dead tier.
type NoViableProviderError struct {
	// Floor is the catalog power tier that was skipped because it had no
	// viable provider. Pass this value back into Next() to bump further.
	Floor int
}

func (e *NoViableProviderError) Error() string {
	return fmt.Sprintf("escalation: no viable provider at floor %d", e.Floor)
}

// Ladder is a MinPower-only escalation ladder. It enumerates the distinct
// power tiers present in a model catalog, sorted ascending, and tracks
// which tiers have at least one viable model.
type Ladder struct {
	tiers     []int
	viableSet map[int]struct{}
}

// NewLadder constructs a Ladder from a model catalog. Models with Power<=0
// are ignored as unrated. A model contributes to the viable set when it is
// both Available and AutoRoutable; non-viable tiers remain present in the
// ladder so Next can report a typed NoViableProviderError when one is hit.
func NewLadder(models []agentlib.ModelInfo) *Ladder {
	seen := map[int]struct{}{}
	viable := map[int]struct{}{}
	for _, m := range models {
		if m.Power <= 0 {
			continue
		}
		seen[m.Power] = struct{}{}
		if m.Available && m.AutoRoutable {
			viable[m.Power] = struct{}{}
		}
	}
	tiers := make([]int, 0, len(seen))
	for p := range seen {
		tiers = append(tiers, p)
	}
	sort.Ints(tiers)
	return &Ladder{tiers: tiers, viableSet: viable}
}

// Tiers returns the distinct catalog power tiers, ascending. The returned
// slice is a copy.
func (l *Ladder) Tiers() []int {
	if l == nil {
		return nil
	}
	out := make([]int, len(l.tiers))
	copy(out, l.tiers)
	return out
}

// Next returns the next power floor strictly greater than actualPower.
//
// actualPower is sourced from the previous attempt's routing-actual record
// (RoutingActual.Power). The escalation loop calls Next(actualPower) after
// a substantive failure to obtain the floor for the next attempt.
//
// Three outcomes:
//
//   - The next catalog tier above actualPower has at least one viable
//     model: returns (floor, nil).
//   - The next catalog tier above actualPower has no viable provider:
//     returns (0, *NoViableProviderError{Floor: tier}). The loop bumps
//     further by calling Next(tier).
//   - No catalog tier above actualPower exists: returns (0, ErrLadderExhausted).
func (l *Ladder) Next(actualPower int) (int, error) {
	if l == nil || len(l.tiers) == 0 {
		return 0, ErrLadderExhausted
	}
	for _, t := range l.tiers {
		if t <= actualPower {
			continue
		}
		if _, ok := l.viableSet[t]; !ok {
			return 0, &NoViableProviderError{Floor: t}
		}
		return t, nil
	}
	return 0, ErrLadderExhausted
}
package escalation

import (
	"errors"
	"testing"

	agentlib "github.com/DocumentDrivenDX/fizeau"
)

func mkModel(power int, available, autoRoutable bool) agentlib.ModelInfo {
	return agentlib.ModelInfo{
		Power:        power,
		Available:    available,
		AutoRoutable: autoRoutable,
	}
}

func viable(power int) agentlib.ModelInfo    { return mkModel(power, true, true) }
func nonviable(power int) agentlib.ModelInfo { return mkModel(power, false, true) }

func TestLadder_Tiers_DistinctAscending(t *testing.T) {
	l := NewLadder([]agentlib.ModelInfo{
		viable(70), viable(50), viable(70), viable(90), viable(50),
	})
	got := l.Tiers()
	want := []int{50, 70, 90}
	if len(got) != len(want) {
		t.Fatalf("Tiers len: got %v want %v", got, want)
	}
	for i := range want {
		if got[i] != want[i] {
			t.Fatalf("Tiers[%d]: got %d want %d (full=%v)", i, got[i], want[i], got)
		}
	}
}

func TestLadder_IgnoresUnratedModels(t *testing.T) {
	l := NewLadder([]agentlib.ModelInfo{
		viable(50),
		mkModel(0, true, true), // unrated
		mkModel(-10, true, true),
		viable(80),
	})
	got := l.Tiers()
	if len(got) != 2 || got[0] != 50 || got[1] != 80 {
		t.Fatalf("Tiers: got %v want [50 80]", got)
	}
}

func TestLadder_Next_AllViable_StepsThroughTiers(t *testing.T) {
	l := NewLadder([]agentlib.ModelInfo{viable(50), viable(70), viable(90)})

	cases := []struct {
		in, want int
	}{
		{0, 50},
		{50, 70},
		{60, 70}, // strictly greater
		{70, 90},
		{89, 90},
	}
	for _, tc := range cases {
		got, err := l.Next(tc.in)
		if err != nil {
			t.Fatalf("Next(%d): unexpected err %v", tc.in, err)
		}
		if got != tc.want {
			t.Fatalf("Next(%d): got %d want %d", tc.in, got, tc.want)
		}
	}
}

func TestLadder_Next_ExhaustedReturnsTypedError(t *testing.T) {
	l := NewLadder([]agentlib.ModelInfo{viable(50), viable(90)})

	if _, err := l.Next(90); !errors.Is(err, ErrLadderExhausted) {
		t.Fatalf("Next(90): err = %v; want ErrLadderExhausted", err)
	}
	if _, err := l.Next(95); !errors.Is(err, ErrLadderExhausted) {
		t.Fatalf("Next(95): err = %v; want ErrLadderExhausted", err)
	}
}

func TestLadder_Next_EmptyCatalogExhausted(t *testing.T) {
	l := NewLadder(nil)
	if _, err := l.Next(0); !errors.Is(err, ErrLadderExhausted) {
		t.Fatalf("empty catalog Next: err = %v; want ErrLadderExhausted", err)
	}
}

func TestLadder_Next_NilReceiverExhausted(t *testing.T) {
	var l *Ladder
	if _, err := l.Next(0); !errors.Is(err, ErrLadderExhausted) {
		t.Fatalf("nil ladder Next: err = %v; want ErrLadderExhausted", err)
	}
}

func TestLadder_Next_SkipTierReturnsNoViableProviderError(t *testing.T) {
	// 50 viable, 70 has only non-viable models, 90 viable.
	l := NewLadder([]agentlib.ModelInfo{
		viable(50),
		nonviable(70),
		viable(90),
	})

	floor, err := l.Next(50)
	if err == nil {
		t.Fatalf("Next(50): expected NoViableProviderError, got floor=%d nil err", floor)
	}
	var nvp *NoViableProviderError
	if !errors.As(err, &nvp) {
		t.Fatalf("Next(50): err = %v; want *NoViableProviderError", err)
	}
	if nvp.Floor != 70 {
		t.Fatalf("NoViableProviderError.Floor: got %d want 70", nvp.Floor)
	}

	// Loop bumps further by calling Next(floor=70).
	got, err := l.Next(nvp.Floor)
	if err != nil {
		t.Fatalf("Next(70) after skip: unexpected err %v", err)
	}
	if got != 90 {
		t.Fatalf("Next(70) after skip: got %d want 90", got)
	}
}

func TestLadder_Next_AllNonViableExhaustsViaSkip(t *testing.T) {
	l := NewLadder([]agentlib.ModelInfo{
		nonviable(50), nonviable(70), nonviable(90),
	})

	// First call returns NoViableProvider for tier 50.
	_, err := l.Next(0)
	var nvp *NoViableProviderError
	if !errors.As(err, &nvp) || nvp.Floor != 50 {
		t.Fatalf("Next(0): want NoViable@50, got %v", err)
	}
	// Bump past 50 → NoViable@70.
	_, err = l.Next(nvp.Floor)
	if !errors.As(err, &nvp) || nvp.Floor != 70 {
		t.Fatalf("Next(50): want NoViable@70, got %v", err)
	}
	// Bump past 70 → NoViable@90.
	_, err = l.Next(nvp.Floor)
	if !errors.As(err, &nvp) || nvp.Floor != 90 {
		t.Fatalf("Next(70): want NoViable@90, got %v", err)
	}
	// Bump past 90 → exhausted.
	_, err = l.Next(nvp.Floor)
	if !errors.Is(err, ErrLadderExhausted) {
		t.Fatalf("Next(90): want ErrLadderExhausted, got %v", err)
	}

