	candidates := []string{sessionID}
	base := filepath.Base(sessionID)
	logDir := ResolveLogDir(projectRoot, "")
	if base != "" {
		candidates = append(candidates,
			filepath.Join(logDir, base),
			filepath.Join(logDir, "agent-"+base),
