func TestWorkJSONOutput_IncludesRouteEconomicsWithoutHumanLines(t *testing.T) {
	var out bytes.Buffer
	err := writeExecuteLoopResult(&out, "/tmp/project", &agent.ExecuteBeadLoopResult{
		Attempts:  1,
