const defaultStrongSplitterMinPower = 90

func resolveStrongSplitterMinPower(ctx context.Context, projectRoot string, rcfg config.ResolvedConfig, svc agentlib.FizeauService) int {
	if svc == nil {
		factory := serviceRunFactory
		if factory == nil {
			factory = NewServiceFromWorkDir
		}
		built, err := factory(projectRoot)
		if err != nil {
			return defaultStrongSplitterMinPower
		}
		svc = built
	}

	filter := agentlib.ModelFilter{}
	if harness := strings.TrimSpace(rcfg.Harness()); harness != "" {
		filter.Harness = harness
	}
	models, err := svc.ListModels(ctx, filter)
	if err != nil {
		return defaultStrongSplitterMinPower
	}
	maxPower := 0
	for _, m := range models {
		if m.Power > maxPower {
			maxPower = m.Power
		}
	}
	if maxPower <= 0 {
		return defaultStrongSplitterMinPower
	}
	return maxPower
}

func isStrongPowerUnsatisfiedError(err error) bool {
	if err == nil {
		return false
	}
	switch ClassifyFailureMode("task_failed", 1, err.Error()) {
	case FailureModeAgentPowerUnsatisfied, FailureModeBlockedByPassthroughConstraint:
		return true
	default:
		return false
	}
